#!/usr/bin/env bash
# topic-5.sh — 行为 决策助手 for 家庭教育指导.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="家庭教育指导"
TOPIC="行为"

usage() {
  cat <<EOF
topic-5.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 2 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-5.sh             # interactive
  ./topic-5.sh --dry-run   # walk through but no file
  ./topic-5.sh --json      # JSON to stdout
  ./topic-5.sh --explain   # show backing playbook rules + mental models
  ./topic-5.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 行为 主题下的 playbook 规则组合成交互树。

基于 2 条规则:
  • 如果 家长说「孩子就是不听话」 → 则 : 则不要直接给行为矫正方案, 先做行为 ABC 功能分析 — 记录 3-5 个典型事件的前因 (什么时候/什么情境) 
  • 如果 发现儿童行为问题可能涉及 ADHD/ASD/抑郁等临床障碍 → 则 : 则必须转介, 不可自行干预 — 用 SDQ 优势与困难问卷做快速筛查 (25 题, 免费, 阳性切点: 情绪症状 ≥

相关心智模型:
  • 关系先于教育 (Connection Before Correction): 家庭教育指导的第一原则不是「教家长正确做法」, 而是先修复或巩固亲子情感连接 — 没有安全依恋基础的教养技术是空中楼阁, Bowlby/Ainsworth 的依恋理论和 Siegel 的「连接先于纠正
  • 行为是信号, 不是问题本身 (Behavior Is a Signal, Not the Problem): 孩子的「问题行为」(发脾气/撒谎/拒学/手机沉迷) 几乎从来不是问题本身, 而是未被满足的需求在呐喊 — Dreikurs 的四个错误目标 (寻求关注/争夺权力/报复/自我放弃) 和 Rosenber

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "家长说「孩子就是不听话」"
  "发现儿童行为问题可能涉及 ADHD/ASD/抑郁等临床障碍"
)
declare -a RULE_ACTIONS=(
  ": 则不要直接给行为矫正方案, 先做行为 ABC 功能分析 — 记录 3-5 个典型事件的前因 (什么时候/什么情境) → 行为 (具体做了什么, 频率多少) → 后果 (家长怎么回应/孩子怎么反应); 再用 Dreikurs 错误目标表诊断行为背后的动机 (寻求关注/争夺权力/报复/自我放弃)"
  ": 则必须转介, 不可自行干预 — 用 SDQ 优势与困难问卷做快速筛查 (25 题, 免费, 阳性切点: 情绪症状 ≥ 7 / 品行问题 ≥ 5); 阳性结果 + 家长/教师双报告一致 → 转介当地三甲医院儿童心理科或发育行为科"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-5-decision"
fi
